// Load Google Identity Services script
const loadGoogleScript = () => {
  return new Promise((resolve) => {
    if (window.google?.accounts?.oauth2) { resolve(); return; }
    const existing = document.getElementById('google-gis');
    if (existing) { existing.onload = resolve; return; }
    const s = document.createElement('script');
    s.id = 'google-gis';
    s.src = 'https://accounts.google.com/gsi/client';
    s.async = true;
    s.defer = true;
    s.onload = resolve;
    document.head.appendChild(s);
  });
};

// Fetch ALL contacts from Google People API (paginated)
export const fetchAllGoogleContacts = async (accessToken) => {
  let allContacts = [];
  let nextPageToken = null;
  let page = 0;
  const maxPages = 20; // safety limit: 20 pages * 1000 = up to 20,000 contacts

  do {
    let url = `${PEOPLE_API_URL}?personFields=names,emailAddresses,organizations,phoneNumbers&pageSize=1000&sortOrder=LAST_MODIFIED_DESCENDING`;
    if (nextPageToken) url += `&pageToken=${nextPageToken}`;

    const res = await fetch(url, {
      headers: { 'Authorization': `Bearer ${accessToken}` }
    });

    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.error?.message || `Google API ${res.status}`);
    }

    const data = await res.json();
    const connections = data.connections || [];

    connections.forEach((person, idx) => {
      const emails = person.emailAddresses || [];
      const names = person.names || [];
      const orgs = person.organizations || [];

      emails.forEach((em) => {
        const name = names[0]?.displayName || em.value.split('@')[0];
        const company = orgs[0]?.name || '';
        const email = em.value;

        // Dedupe by email
        if (!allContacts.find(c => c.email.toLowerCase() === email.toLowerCase())) {
          allContacts.push({
            id: `gmail_${allContacts.length + 1}_${Date.now()}`,
            name,
            email,
            company,
            tags: [],
            source: 'GMAIL',
          });
        }
      });
    });

    nextPageToken = data.nextPageToken || null;
    page++;
  } while (nextPageToken && page < maxPages);

  return allContacts;
};

// Fetch "Other Contacts" - people you've emailed but not saved
export const fetchOtherContacts = async (accessToken) => {
  let allOther = [];
  let nextPageToken = null;
  let page = 0;
  const maxPages = 20;

  do {
    let url = `${OTHER_CONTACTS_URL}?readMask=names,emailAddresses,phoneNumbers&pageSize=1000`;
    if (nextPageToken) url += `&pageToken=${nextPageToken}`;

    const res = await fetch(url, {
      headers: { 'Authorization': `Bearer ${accessToken}` }
    });

    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      console.error('[OtherContacts] Error:', res.status, err.error?.message || JSON.stringify(err));
      break;
    }

    const data = await res.json();
    const contacts = data.otherContacts || [];

    contacts.forEach((person) => {
      const emails = person.emailAddresses || [];
      const names = person.names || [];
      const orgs = person.organizations || [];

      emails.forEach((em) => {
        const name = names[0]?.displayName || em.value.split('@')[0];
        const company = orgs[0]?.name || '';
        const email = em.value;

        if (!allOther.find(c => c.email.toLowerCase() === email.toLowerCase())) {
          allOther.push({
            id: `gmail_other_${allOther.length + 1}_${Date.now()}`,
            name,
            email,
            company,
            tags: [],
            source: 'GMAIL',
          });
        }
      });
    });

    nextPageToken = data.nextPageToken || null;
    page++;
  } while (nextPageToken && page < maxPages);

  return allOther;
};

